#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 50000
#define MAX_M 50000
#define MAX_K 100000

// Define the structure for a tree node
typedef struct Node {
    int id;
    struct Node** neighbors;
    int numNeighbors;
} Node;

// Function to create a new node
Node* createNode(int id) {
    Node* node = (Node*) malloc(sizeof(Node));
    node->id = id;
    node->neighbors = NULL;
    node->numNeighbors = 0;
    return node;
}

// Function to add a neighbor to a node
void addNeighbor(Node* node, Node* neighbor) {
    node->numNeighbors++;
    node->neighbors = (Node**) realloc(node->neighbors, node->numNeighbors * sizeof(Node*));
    node->neighbors[node->numNeighbors - 1] = neighbor;
}

// Function to traverse the tree and count the number of vertices that, when removed, will result in all vertices from the query being in separate connected components
int traverse(Node* node, int* query, int numQuery) {
    int count = 0;
    // Traverse the tree using DFS
    int* visited = (int*) calloc(MAX_N, sizeof(int));
    int* stack = (int*) malloc(MAX_N * sizeof(int));
    int top = 0;
    stack[top++] = node->id;
    while (top > 0) {
        int current = stack[--top];
        visited[current] = 1;
        // Check if the current node is in the query
        int inQuery = 0;
        for (int i = 0; i < numQuery; i++) {
            if (query[i] == current) {
                inQuery = 1;
                break;
            }
        }
        // If the current node is not in the query, check its neighbors
        if (!inQuery) {
            for (int i = 0; i < node->numNeighbors; i++) {
                Node* neighbor = node->neighbors[i];
                if (!visited[neighbor->id]) {
                    stack[top++] = neighbor->id;
                }
            }
        }
        // If the current node is in the query, check if its removal will result in all vertices from the query being in separate connected components
        else {
            int separate = 1;
            for (int i = 0; i < numQuery; i++) {
                if (query[i] != current && !visited[query[i]]) {
                    separate = 0;
                    break;
                }
            }
            if (separate) {
                count++;
            }
        }
    }
    free(visited);
    free(stack);
    return count;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        Node** nodes = (Node**) malloc(N * sizeof(Node*));
        for (int i = 0; i < N; i++) {
            nodes[i] = createNode(i + 1);
        }
        for (int i = 0; i < N - 1; i++) {
            int Xi, Yi;
            scanf("%d %d", &Xi, &Yi);
            addNeighbor(nodes[Xi - 1], nodes[Yi - 1]);
            addNeighbor(nodes[Yi - 1], nodes[Xi - 1]);
        }
        for (int i = 0; i < M; i++) {
            int Ki;
            scanf("%d", &Ki);
            int* query = (int*) malloc(Ki * sizeof(int));
            for (int j = 0; j < Ki; j++) {
                scanf("%d", &query[j]);
            }
            int count = traverse(nodes[0], query, Ki);
            printf("%d\n", count);
            free(query);
        }
        for (int i = 0; i < N; i++) {
            free(nodes[i]->neighbors);
            free(nodes[i]);
        }
        free(nodes);
    }
    return 0;
}

